 14	import PaneBody from '../layout/PaneBody';
 15	import { SecretKind } from '../../types';
 16	import { ExternalLink } from '../utils/link';
 17	import {
 18	  ListPageHeader,
 19	  NamespaceBar,
 20	  ResourceLink,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import { SecretModel } from '../../models';
 23	import { Breadcrumbs } from '../common/Breadcrumbs';
 24	
 25	import './PacPage.scss';
 26	
 27	type PacOverviewProps = {
 28	  namespace: string;
 29	  secret?: SecretKind;
 30	  loadError?: Error;
 31	  showSuccessAlert?: boolean;
 32	};
 33	
 34	const PacOverview: React.FC<PacOverviewProps> = ({
 35	  namespace,
 36	  secret,
 37	  loadError,
 38	  showSuccessAlert = false,
 39	}) => {
 40	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 41	  const [alertVisible, setAlertVisible] =
 42	    React.useState<boolean>(showSuccessAlert);
 43	
 44	  React.useEffect(() => {
 45	    setAlertVisible(showSuccessAlert);
 46	  }, [showSuccessAlert]);
 47	
 48	  const breadcrumbs = [
 49	    {
 50	      name: t('Pipelines'),
 51	      path: `/pipelines/ns/${namespace}`,
 52	    },
 53	    {
 54	      name: t('GitHub App details'),
 55	      path: undefined,
 56	    },
 57	  ];
 58	  if (loadError || !secret?.metadata) {
 59	    return (
 60	      <>
 61	        <NamespaceBar isDisabled={true} />
 62	        <PageSection
 63	          type="breadcrumb"
 64	          className="co-m-nav-title--detail pipelines-console-plugin__background-transparent"
 65	        >
 66	          <Breadcrumbs breadcrumbs={breadcrumbs} />
 67	        </PageSection>
 68	        <ListPageHeader title={t('GitHub App Details')}></ListPageHeader>
 69	        <PageBody>
 70	          <PaneBody className="pipelines-console-plugin__background-transparent">
 71	            <Alert
 72	              variant="danger"
 73	              title={t('Something unexpected happened!!')}
 74	              data-testId="danger-alert"
 75	            >
 76	              {loadError?.message && <p>{loadError.message}</p>}
 77	            </Alert>
 78	          </PaneBody>
 79	        </PageBody>
 80	      </>
 81	    );
 82	  }
 83	
 84	  const {
 85	    metadata: { name, namespace: secretNs, annotations },
 86	  } = secret;
 87	
 88	  return (
 89	    <>
 90	      <NamespaceBar isDisabled={true} />
 91	      <PageSection
 92	        type="breadcrumb"
 93	        className="co-m-nav-title--detail pipelines-console-plugin__background-transparent"
 94	      >
 95	        <Breadcrumbs breadcrumbs={breadcrumbs} />
 96	      </PageSection>
 97	      <ListPageHeader title={t('GitHub App Details')}></ListPageHeader>
 98	
 99	      <PageBody data-test="PageBody">
100	        <PaneBody
101	          data-test="PaneBody"
102	          className="pipelines-console-plugin__background-transparent"
103	        >
104	          {alertVisible && (
105	            <Alert
106	              variant="success"
107	              title={t('You have successfully setup the GitHub App')}
108	              actionClose={
109	                <AlertActionCloseButton
110	                  onClose={() => setAlertVisible(false)}
111	                />
112	              }
113	              data-testId="success-alert"
114	            >
115	              {annotations?.appUrl && (
116	                <Trans t={t} ns="plugin__pipelines-console-plugin">
117	                  <p>
118	                    Use the{' '}
119	                    <ExternalLink href={annotations.appUrl}>link</ExternalLink>{' '}
120	                    to install the newly created GitHub application to your
121	                    repositories in your organization/account
122	                  </p>
123	                </Trans>
124	              )}
125	            </Alert>
126	          )}
127	          {!showSuccessAlert && annotations?.appUrl && (
128	            <Hint
129	              className="pipelines-console-plugin__background-transparent opp-github-app-hint-section"
130	              data-testid="hint-section-id"
131	            >
132	              <HintBody>
133	                <Trans t={t} ns="plugin__pipelines-console-plugin">
134	                  Use this{' '}
135	                  <ExternalLink href={annotations.appUrl}>link</ExternalLink> to
136	                  install the GitHub Application to your repositories in your
137	                  organization/account.
138	                </Trans>
139	              </HintBody>
140	            </Hint>
141	          )}
142	          <br />
143	          <FormGroup fieldId="app-overview">
144	            {annotations?.appName && (
145	              <FormGroup label={t('App Name')} fieldId="app-name">
146	                <Text component={TextVariants.small}>
147	                  {annotations.appName}
148	                </Text>
149	              </FormGroup>
150	            )}
151	            <br />
152	            {annotations?.appUrl && (
153	              <FormGroup label={t('App Link')} fieldId="app-link">
154	                <ExternalLink
155	                  text={annotations.appUrl}
156	                  href={annotations.appUrl}
157	                />
158	              </FormGroup>
159	            )}
160	            <br />
161	            <FormGroup label={t('Secret')} fieldId="res-secret">
162	              <ResourceLink
163	                kind={SecretModel.kind}
164	                name={name}
165	                namespace={secretNs}
166	              />
167	            </FormGroup>
168	            <br />
169	          </FormGroup>
170	        </PaneBody>
171	      </PageBody>
172	    </>
173	  );
174	};
175	
176	export default PacOverview;

