 1	import * as React from 'react';
 2	import { render, screen } from '@testing-library/react';
 3	import PacOverview from '../PacOverview';
 4	import { sampleSecretData } from '../../../test-data/pac-data';
 5	
 6	jest.mock('../hooks/usePacGHManifest', () => ({
 7	  usePacGHManifest: jest.fn(),
 8	}));
 9	
10	jest.mock('@openshift-console/dynamic-plugin-sdk', () => ({
11	  NamespaceBar: () => <div data-test="mock-namespace-bar" />,
12	  ListPageHeader: () => <div data-test="mock-list-page-header" />,
13	  ResourceLink: (props: any) => (
14	    <div data-test="mock-resource-link">{JSON.stringify(props)}</div>
15	  ),
16	}));
17	
18	jest.mock('../../common/LinkTo', () => ({
19	  LinkTo: () => 'a',
20	}));
21	
22	describe('PacOverview', () => {
23	  const defaultProps = {
24	    namespace: 'openshift-pipelines',
25	    secret: sampleSecretData,
26	  };
27	
28	  it('should show success alert if first flow and secret exists', () => {
29	    render(<PacOverview {...defaultProps} showSuccessAlert />);
30	    expect(screen.getByTestId('success-alert')).toBeDefined();
31	  });
32	
33	  it('should not show success alert if not first flow and secret exists', () => {
34	    render(<PacOverview {...defaultProps} />);
35	    expect(screen.queryByTestId('success-alert')).toBeNull();
36	  });
37	
38	  it('should show hint if not first flow and secret exists', () => {
39	    render(<PacOverview {...defaultProps} />);
40	    expect(screen.getByTestId('hint-section-id')).toBeDefined();
41	  });
42	
43	  it('should not show hint if first flow', () => {
44	    render(<PacOverview {...defaultProps} showSuccessAlert />);
45	    expect(screen.queryByTestId('hint-section-id')).toBeNull();
46	  });
47	
48	  it('should show danger alert if there is an error', () => {
49	    render(<PacOverview {...defaultProps} loadError={new Error('error')} />);
50	    const alertTitle = screen.getByTestId('danger-alert');
51	    expect(alertTitle).toBeDefined();
52	    const alertContainer = alertTitle.closest('.pf-m-danger');
53	    expect(alertContainer).toBeTruthy();
54	  });
55	
56	  it('should show danger alert if secret does not exist', () => {
57	    render(<PacOverview {...defaultProps} secret={undefined} />);
58	    const alertTitle = screen.getByTestId('danger-alert');
59	    expect(alertTitle).toBeDefined();
60	    const alertContainer = alertTitle.closest('.pf-m-danger');
61	    expect(alertContainer).toBeTruthy();
62	  });
63	});

